"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeReorder — write surface for placing a PO.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Opertation/
   magellan-bridge-reorder.html

   The verb spine. Pattern:
   - SKU summary (stats with cover/on-hand/velocity/landed)
   - "The order" form: qty + auto covers, supplier + auto arrives, cost
     breakdown with order total
   - Verdict (BUY / HOLD / WAIT) with 4 factor dots
   - "What this does to your cash" — 2 tiers (This order + Runway after)
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";

// SKU being reordered (demo)
const SKU = {
  name: "Pastel Tulip Bouquet",
  meta: "Bouquets · Kunming Flowers · 7-day lead",
  cover: 2.1,
  onHand: 42,
  velocity: 20,
  landed: 362,
  retail: 1290, // for CM1 calc
  moq: 12000,
};

const SUPPLIERS = [
  { name: "Kunming Flowers", lead: 7 },
  { name: "Nordic Floral", lead: 2 },
  { name: "Local Market", lead: 0 },
];

const CASH_NOW = 214000;

const fmtUSD = (v: number) => {
  const abs = Math.abs(v);
  if (abs >= 1_000_000) return `$${(abs / 1_000_000).toFixed(2).replace(/\.?0+$/, "")}M`;
  if (abs >= 1000) return `$${Math.round(abs / 1000)}K`;
  return `$${Math.round(abs)}`;
};
const fmtUSDExact = (v: number) => `$${Math.round(v).toLocaleString()}`;

function addDays(start: Date, days: number) {
  const d = new Date(start);
  d.setDate(d.getDate() + days);
  return d;
}
function fmtDate(d: Date) {
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
}

export function BridgeReorder() {
  const { setPage } = useBridge();

  const [qty, setQty] = useState("280");
  const [supplier, setSupplier] = useState(SUPPLIERS[0]);
  const [openMenu, setOpenMenu] = useState<"supplier" | null>(null);
  const [placed, setPlaced] = useState(false);

  const qtyN = useMemo(() => {
    const n = parseInt(qty.replace(/[^0-9]/g, ""), 10);
    return isNaN(n) ? 0 : n;
  }, [qty]);

  const orderCost = qtyN * SKU.landed;
  const coversDays = SKU.velocity > 0 ? Math.round(qtyN / SKU.velocity) : 0;
  const arrivesIn = supplier.lead;

  const today = new Date();
  const arrives = addDays(today, arrivesIn);
  const dueDate = addDays(arrives, 30);
  const cashAfter = CASH_NOW - orderCost;
  const monthlyBurn = 37000; // proxy from demo
  const runwayNow = CASH_NOW / monthlyBurn;
  const runwayAfter = cashAfter / monthlyBurn;
  const revenue = qtyN * SKU.retail;
  const roc = orderCost > 0 ? revenue / orderCost : 0;
  const cm1 = Math.round(((SKU.retail - SKU.landed) / SKU.retail) * 100);

  const moqCleared = orderCost >= SKU.moq;

  // Verdict logic
  const profitable = cm1 >= 30;
  const sellsFast = SKU.velocity >= 5;
  const headroom = coversDays >= 7 && coversDays <= 30;
  const overstock = coversDays > 45;
  const late = SKU.cover < supplier.lead;

  const verdict = !profitable
    ? "wait"
    : overstock
      ? "hold"
      : "buy";

  const verdictMark = verdict === "buy" ? "BUY" : verdict === "hold" ? "HOLD" : "WAIT";
  const verdictLine =
    verdict === "buy"
      ? "Worth reordering — this SKU sells, it's profitable at landed cost, and you have demand headroom."
      : verdict === "hold"
        ? "Hold — this would overstock. You're already covered well past lead time; reorder later."
        : "Wait — margin is thin at landed. Renegotiate cost or reduce qty before buying more.";

  const place = () => {
    setPlaced(true);
    setTimeout(() => {
      setPlaced(false);
      setPage("home");
    }, 1800);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M3 7 h13 l-3 -3 M3 7 l3 3" />
            <path d="M21 17 h-13 l3 3 M21 17 l-3 -3" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Reorder</div>
          <div className="bridge-page-head-sub">
            Magellan reads the SKU, weighs whether it&rsquo;s worth buying, and shows what the order does to your cash.
          </div>
        </div>
      </div>

      {/* The SKU summary */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">{SKU.name}</div>
          <div className="bridge-rb-sku-meta">{SKU.meta}</div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v alert">{SKU.cover}</span>
            <span className="bridge-rb-stat-k">days of cover left</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{SKU.onHand}</span>
            <span className="bridge-rb-stat-k">on hand</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">~{SKU.velocity}</span>
            <span className="bridge-rb-stat-k">/day velocity</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">${SKU.landed}</span>
            <span className="bridge-rb-stat-k">landed cost</span>
          </div>
        </div>
      </div>

      {/* The order card */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">The order</span>
          <span className="bridge-ni-source manual">✏ Magellan suggests — adjust freely</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Order quantity</span>
            <input
              className="bridge-ni-input"
              type="text"
              value={qty}
              onChange={(e) => setQty(e.target.value)}
            />
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Covers</span>
            <div className="bridge-ni-readout">
              {coversDays > 0 ? `~${coversDays} days` : "—"}
            </div>
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Supplier</span>
            <div
              className={`bridge-ni-select${openMenu === "supplier" ? " open" : ""}`}
              onClick={() => setOpenMenu((m) => (m === "supplier" ? null : "supplier"))}
            >
              <span>{supplier.name}</span>
              <span className="meta">{supplier.lead}-day lead</span>
              <span className="chev">▾</span>
              {openMenu === "supplier" && (
                <div className="bridge-ni-menu open">
                  {SUPPLIERS.map((s) => (
                    <div
                      key={s.name}
                      className="bridge-ni-menu-item"
                      onClick={(e) => {
                        e.stopPropagation();
                        setSupplier(s);
                        setOpenMenu(null);
                      }}
                    >
                      {s.name}
                      <span className="sub">{s.lead}d lead</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Arrives</span>
            <div className="bridge-ni-readout">
              in ~{arrivesIn} day{arrivesIn === 1 ? "" : "s"} · {fmtDate(arrives)}
            </div>
          </div>

          <div className="bridge-ni-cost">
            <div className="bridge-ni-cost-head">
              <span className="bridge-ni-label">Order cost</span>
              <span className="bridge-ni-cost-note">qty × landed</span>
            </div>
            <div className="bridge-ni-cost-row">
              <span>
                {qtyN.toLocaleString()} units × ${SKU.landed} landed
              </span>
              <span className="bridge-rb-num">{fmtUSDExact(orderCost)}</span>
            </div>
            <div className="bridge-ni-cost-row add">
              <span>vs MOQ ({fmtUSDExact(SKU.moq)})</span>
              <span className={`bridge-rb-num${moqCleared ? " good" : ""}`}>
                {moqCleared ? "cleared" : "below MOQ"}
              </span>
            </div>
            <div className="bridge-ni-cost-total">
              <span className="lbl">Order total</span>
              <span className="bridge-ni-landed">{fmtUSDExact(orderCost)}</span>
            </div>
          </div>
        </div>
      </div>

      {/* The verdict */}
      <div className={`bridge-rb-verdict ${verdict === "buy" ? "" : verdict === "hold" ? "hold" : "wait"}`}>
        <div
          className="bridge-rb-verdict-mark"
          style={
            verdict === "buy"
              ? { color: "var(--d-finance)", width: 74 }
              : undefined
          }
        >
          {verdictMark}
        </div>
        <div className="bridge-rb-verdict-body">
          <div className="bridge-rb-verdict-line">{verdictLine}</div>
          <div className="bridge-rb-verdict-factors">
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${sellsFast ? "ok" : "bad"}`} />
              <span className="bridge-rb-factor-k">Sells</span>
              <span className="bridge-rb-factor-v">
                ~{SKU.velocity}/day, steady
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${profitable ? "ok" : "bad"}`} />
              <span className="bridge-rb-factor-k">Profitable at landed</span>
              <span className="bridge-rb-factor-v">
                {cm1}% CM1 on ${SKU.landed}, not invoice
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${overstock ? "warn" : headroom ? "ok" : "warn"}`} />
              <span className="bridge-rb-factor-k">Demand headroom</span>
              <span className="bridge-rb-factor-v">
                {overstock
                  ? `${coversDays} days cover — would overstock`
                  : `${coversDays} days cover, no overstock risk`}
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${late ? "warn" : "ok"}`} />
              <span className="bridge-rb-factor-k">Timing</span>
              <span className="bridge-rb-factor-v">
                {late
                  ? `${SKU.cover} days left vs ${supplier.lead}-day lead — you're late, order now`
                  : `${SKU.cover} days left, ${supplier.lead}-day lead — comfortable`}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* What this does to your cash */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this does to your cash
          <span className="bridge-ni-outcome-prov firm">Computed from your ledger</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">This order</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Cash out</span>
              <span className="v">{fmtUSD(orderCost)}</span>
              <span className="kk">on Net 30 terms</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Due date</span>
              <span className="v">{fmtDate(dueDate)}</span>
              <span className="kk">30 days after delivery</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Revenue it unlocks</span>
              <span className="v good">{fmtUSD(revenue)}</span>
              <span className="kk">
                {qtyN.toLocaleString()} units at ${SKU.retail.toLocaleString()}
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Return on capital</span>
              <span className="v good">{roc.toFixed(1)}×</span>
              <span className="kk">over the sell-through</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Runway after this</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Cash now</span>
              <span className="v">{fmtUSD(CASH_NOW)}</span>
              <span className="kk">spendable</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">After this PO clears</span>
              <span className={`v${cashAfter < 50000 ? " alert" : ""}`}>
                {fmtUSD(cashAfter)}
              </span>
              <span className="kk">when due {fmtDate(dueDate)}</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Runway</span>
              <span className={`v${runwayAfter < 3 ? " alert" : ""}`}>
                {runwayNow.toFixed(1)} → {runwayAfter.toFixed(1)} <small>mo</small>
              </span>
              <span className="kk">
                {runwayAfter < 3 ? "tight" : "still healthy"}
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Other POs due same window</span>
              <span className="v">$48K</span>
              <span className="kk">Kunming #4130</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          The verdict weighs <b>velocity × margin-at-landed × demand headroom</b> — not just &ldquo;are you low.&rdquo; Cash figures come from your <b>ledger</b> and the PO calendar, so the runway shift is real. This PO and any others due in the same window are shown together so you don&rsquo;t commit past your cash.
        </div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the PO — <b>nothing is sent</b> to the supplier until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Hold off
          </button>
          <button
            className={`bridge-ni-create${placed ? " done" : ""}`}
            type="button"
            onClick={place}
            disabled={placed || qtyN <= 0}
          >
            {placed ? `PO drafted ✓` : `Place order — ${fmtUSD(orderCost)} →`}
          </button>
        </div>
      </div>
    </div>
  );
}
